={
  "model": "llama3.2:latest",
  "prompt": "Task: Create a structured description for a PURELY ABSTRACT art sequence focusing on HIGH-DISPLACEMENT PHYSICAL MOTION.

Variables:
- Atmosphere: {{ $json.atmosphere }}
- Texture: {{ $json.texture }}
- Palette: {{ $json.palette }}
- Lighting: {{ $json.lighting }}
- Motion: {{ $json.motion }}
- Quality: {{ $json.quality_boosters }}

Negative Constraints: {{ $json.negatives }}

Return ONLY a JSON object:
1. 'image_prompt': Start with '[Palette] [Texture]'. Create a one-sentence description focusing on 'Macro photography of {{ $json.texture }} in {{ $json.palette }} with {{ $json.lighting }} within {{ $json.atmosphere }}. {{ $json.quality_boosters }}'.
2. 'motion_description': Begin with the primary action verb from '{{ $json.motion }}'. Describe a radical physical transformation across the X, Y, and Z axes. Use high-action verbs like 'extrude', 'spiral', 'displace', or 'reconfigure'. Avoid words like 'flicker', 'shimmer', or 'pulse'. Ensure elements move significantly across the frame.

Final Instruction: The motion must be mechanical or physical, not just light changing. NO metaphors.",
  "stream": false,
  "format": "json",
  "options": {
    "temperature": 1.1,
    "seed": {{ $json.seed }}
  }
}

parameters.jsCode:
const inputData = $input.item.json;
let rawContent = "";

// 1. EXTRACT RAW CONTENT
if (inputData.response) {
    rawContent = inputData.response; 
} else if (inputData.message && inputData.message.content) {
    rawContent = inputData.message.content;
} else if (typeof inputData === 'string') {
    rawContent = inputData;
} else {
    rawContent = JSON.stringify(inputData);
}

// 2. PARSE AND VALIDATE
let data = { image_prompt: "", motion_description: "" };

try {
    let parsedOuter;
    try {
        parsedOuter = JSON.parse(rawContent);
    } catch (e) {
        const match = rawContent.match(/\{[\s\S]*\}/);
        if (!match) throw new Error("No JSON structure found.");
        parsedOuter = JSON.parse(match[0]);
    }
    if (parsedOuter) {
        let innerContent = parsedOuter.response || parsedOuter;
        let finalData = (typeof innerContent === 'string') ? JSON.parse(innerContent) : innerContent;
        data.image_prompt = finalData.image_prompt;
        data.motion_description = finalData.motion_description;
    }
} catch (e) {
    throw new Error(`STRICT VALIDATION FAILED: ${e.message}`);
}

// 3. DYNAMIC PATHING
const d = new Date();
const batchFolder = `Batch_${d.getFullYear()}${(d.getMonth()+1).toString().padStart(2, '0')}${d.getDate().toString().padStart(2, '0')}_${d.getHours().toString().padStart(2, '0')}${d.getMinutes().toString().padStart(2, '0')}`;

// 4. THE ULTRA EYE CANDY WORKFLOW (REVISED)
let workflow = {
  // --- FLUX GEN (30 STEPS FOR ULTRA DETAIL) ---
  "132:1": { "inputs": { "scheduler": "karras", "steps": 30, "denoise": 1.0, "model": ["132:7", 0] }, "class_type": "BasicScheduler" },
  "132:2": { "inputs": { "sampler_name": "euler_ancestral" }, "class_type": "KSamplerSelect" },
  "132:3": { "inputs": { "guidance": 4.5, "conditioning": ["132:17", 0] }, "class_type": "FluxGuidance" },
  "132:4": { "inputs": { "model": ["132:7", 0], "conditioning": ["132:3", 0] }, "class_type": "BasicGuider" },
